mapper.select:
SELECT  FROM customs_products_list
WHERE sku IN
#{sku}

SELECT od.overseas_order_no AS overseasOrderNo, COUNT(DISTINCT od.sku) AS productCount, CAST(SUM(GREATEST(IFNULL(od.package_num, 0), 0)) AS SIGNED) AS totalBoxCount, SUM(GREATEST(IFNULL(od.package_num, 0), 0) * GREATEST(IFNULL(od.quantity_in_case, 1), 1)) AS totalQuantity, SUM(IFNULL(od.total_box_weight, IFNULL(od.cg_box_weight, 0) * GREATEST(IFNULL(od.package_num, 1), 1))) AS totalGrossWeight FROM overseas_stock_order_detail od WHERE od.overseas_order_no IS NOT NULL AND od.overseas_order_no != ''
AND od.overseas_order_no LIKE CONCAT('%', #{keyword}, '%')
GROUP BY od.overseas_order_no ORDER BY od.overseas_order_no DESC LIMIT #{limit}

SELECT 
FROM overseas_stock_order_detail od
INNER JOIN customs_products_list p ON p.sku COLLATE utf8mb4_unicode_ci = od.sku COLLATE utf8mb4_unicode_ci
WHERE od.overseas_order_no IN
#{order}
ORDER BY FIELD(od.overseas_order_no,
#{order}
), od.id

SELECT b.shipment_id AS shipmentId, COUNT(DISTINCT b.sku) AS productCount, CAST(SUM(GREATEST(IFNULL(b.box_num, 1), 1)) AS SIGNED) AS totalBoxCount, SUM( IF(b.quantity_in_case IS NOT NULL AND b.quantity_in_case REGEXP '^[0-9.]+$', CAST(b.quantity_in_case AS DECIMAL(12,4)), 1) * GREATEST(IFNULL(b.box_num, 1), 1) ) AS totalQuantity, SUM( IF(b.box_weight IS NOT NULL AND b.box_weight REGEXP '^[0-9.]+$', CAST(b.box_weight AS DECIMAL(12,4)) * IF(UPPER(IFNULL(b.box_weight_unit, 'KG')) IN ('LB', 'LBS'), 0.45359237, 1) * GREATEST(IFNULL(b.box_num, 1), 1), 0) ) AS totalGrossWeight FROM amz_fba_shipment_box b WHERE b.shipment_id IS NOT NULL AND b.shipment_id != ''
AND b.shipment_id LIKE CONCAT('%', #{keyword}, '%')
GROUP BY b.shipment_id ORDER BY MAX(b.id) DESC LIMIT #{limit}

SELECT 
FROM amz_fba_shipment_box b
INNER JOIN customs_products_list p ON p.sku COLLATE utf8mb4_unicode_ci = b.sku COLLATE utf8mb4_unicode_ci
WHERE b.shipment_id IN
#{shipment}
ORDER BY FIELD(b.shipment_id,
#{shipment}
), b.id
